use std::sync::{Arc, Mutex};
use std::thread;

struct Inventory {
    stock_levels: Vec<i32>,
}

impl Inventory {
    fn new(stock_levels: Vec<i32>) -> Self {
        Inventory { stock_levels }
    }

    fn check_stock(&self, product_id: i32) -> bool {
        self.stock_levels[product_id as usize] > 0
    }

    fn decrement_inventory(&mut self, product_id: i32) {
        let mut lock = self.stock_levels.write().unwrap();
        *lock.get_mut(product_id as usize).unwrap() -= 1;
    }
}

fn main() {
    let inventory = Arc::new(Mutex::new(Inventory::new(vec![10, 20, 30])));

    let mut handles = vec![];

    for i in 0..5 {
        let inventory_clone = Arc::clone(&inventory);
        let handle = thread::spawn(move || {
            if inventory_clone.lock().unwrap().check_stock(0) {
                inventory_clone.lock().unwrap().decrement_inventory(0);
            }
        });
        handles.push(handle);
    }

    for handle in handles {
        handle.join().unwrap();
    }
}